/* CHRYS 1/9/2022 SELECT DISTINCT B.PEN_INST_CODE_TO INST_CODE_AYTOT, C.PENSION_IKA_INST_NAME INST_NAME_AYTOT FROM PEN_ACCOUNT A, PEN_APPL_INSTITUTIONS_DA B, COM_PENSION_IKA_INSTITUTION C WHERE A.ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR -- CHRYS 1/9/2022 AND A.PAI_PDTA_APPLICATION_UNIT_CODE = B.PDTA_APPLICATION_UNIT_CODE AND A.PAI_PDTA_APPLICATION_YEAR = B.PDTA_APPLICATION_YEAR AND A.PAI_APPLICATION_INCR_SEQ_NO = B.APPLICATION_INCR_SEQ_NO AND B.PEN_INST_CODE_TO = C.PENSION_IKA_INST_CODE AND B.STATUS = '1' AND B.AYTOTELES_FLG = '1' ; -- ΑΥΤΟΤΕΛΗΣ ΦΟΡΕΑΣ
*/
-- CHRYS 1/9/2022 SELECT DISTINCT B.PEN_INST_CODE_TO INST_CODE_AYTOT, C.PENSION_IKA_INST_NAME INST_NAME_AYTOT FROM PEN_ACCOUNT A, PEN_APPL_INSTITUTIONS_DA B, COM_PENSION_IKA_INSTITUTION C WHERE A.ACCOUNT_NO = :P_ACC_ACCOUNT_NO AND A.PAI_PDTA_APPLICATION_UNIT_CODE = DECODE(:CF_PAD_ID, NULL, B.PDTA_APPLICATION_UNIT_CODE, A.PAI_PDTA_APPLICATION_UNIT_CODE) AND A.PAI_PDTA_APPLICATION_YEAR = DECODE(:CF_PAD_ID, NULL, B.PDTA_APPLICATION_YEAR, A.PAI_PDTA_APPLICATION_YEAR) AND A.PAI_APPLICATION_INCR_SEQ_NO = DECODE(:CF_PAD_ID, NULL, B.APPLICATION_INCR_SEQ_NO,A.PAI_APPLICATION_INCR_SEQ_NO) AND B.PAD_ID_FK = NVL(:CF_PAD_ID, B.PAD_ID_FK) AND B.PEN_INST_CODE_TO = C.PENSION_IKA_INST_CODE AND B.STATUS = '1' AND B.AYTOTELES_FLG = '1' ; -- ΑΥΤΟΤΕΛΗΣ ΦΟΡΕΑΣ -- END CHRYS 1/9/2022

