      function CF_22Formula return Number is
begin
 IF :P_IS_OGA = 0 THEN
  ---SPAP 26/04/2021 ΤΟ ΕΒΑΛΑ ΑΥΤΟ ΓΙΑΤΙ ΤΟ ΠΕΔΙΟ ΕΙΧΕ ΕΠΑΝΩ ΤΗΝ CF_32 ΠΟΥ ΑΥΤΗ ΕΧΕΙ ΣΧΟΛΙΑ ΟΤΙ ΠΑΛΙΑ ΕΜΦΑΝΙΖΟΤΑΝ Η CF_22. 
	---ΣΕ ΚΑΠΟΙΕΣ ΠΕΡΙΠΤΩΣΕΙΣ ΔΕΝ ΕΜΦΑΝΙΖΕ ΤΟ ΚΑΤΑΒΛΗΤΕΟ ΠΟΣΟ ΟΠΟΤΕ ΕΒΑΛΑ ΤΟ ΚΑΤΩΘΙ
	IF NVL(:CF_32,0) > 0 THEN 
	  RETURN :CF_32;
	ELSE
		RETURN(NVL(:CF_20,0) + NVL(:CF_21,0) + NVL(:CF_19,0)) /* CHRYS 5/7/2021 */ + NVL(:CF_56,0);
	END IF;			
 ELSE
   RETURN :cp_OGA_SYMFEROTERO_MELOS;
 END IF;  		
end;

