      function CF_TSMEDE_AMTFormula return Number is

CURSOR 	CUR_INTRODUCTION IS
SELECT     C.INTRODUCTION_CODE
FROM       PEN_ACCOUNT A,
           PEN_QC_PER_PRODINST B,
           PEN_PRODUCT_PER_INSTITUTIONS C
WHERE      A.ACCOUNT_NO  = :P_ACC_ACCOUNT_NO_DIR
AND        A.QCPRODINS_QC_PER_PRODINST_CODE = B.QC_PER_PRODINST_CODE
AND        B.PRODUCT_PER_INSTITUTION_CODE = C.PRODUCT_PER_INSTITUTION_CODE  ;

V_INTRODUCTION		PEN_PRODUCT_PER_INSTITUTIONS.INTRODUCTION_CODE%TYPE;

begin
	COMBAT_DEBUGING('P_ACC_ACCOUNT_NO_DIR='||:P_ACC_ACCOUNT_NO_DIR, 'CHRYS_REPORTS');
	OPEN		CUR_INTRODUCTION;
	FETCH		CUR_INTRODUCTION
	INTO 		V_INTRODUCTION;
	CLOSE		CUR_INTRODUCTION;
	
  IF V_INTRODUCTION = '00012' THEN
  	RETURN (1524.60);
  ELSE
  	RETURN 0;
  END IF;
end;

      function CF_28Formula return Number is
V_NUM	  NUMBER;
V_NUM_1	NUMBER;
V_NUM_2	NUMBER;

CURSOR CUR IS
SELECT  ((sum(NVL(MONTH_INCOME_INFLATED,0)+NVL(RETRO_AMT_INFLATED,0))*25)/sum(NVL(MONTH_DAYS,0)))  
FROM PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR; 

CURSOR CUR_1 IS
SELECT   NVL(POSOSTO_ANAPL,0)+ NVL(ADAPOD_PERCENT_KSB,0)
FROM  PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR;

CURSOR CUR_2 IS
SELECT ADAPODOTIKH_AMT
FROM   PEN_CALC_ADAPOD_RESULTS
WHERE  ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR;

begin
  
  OPEN CUR;
  FETCH CUR 
  INTO V_NUM;
  CLOSE CUR;
  
  
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
  
  OPEN CUR_2;
  FETCH CUR_2 
  INTO V_NUM_2;
  CLOSE CUR_2;
  
  
  IF V_NUM_2 IS NOT NULL AND V_NUM_2 != 0 THEN
  	RETURN V_NUM_2;
  ELSE
	  RETURN (NVL(V_NUM,0)*NVL(V_NUM_1,0))/100;
  END IF;
  
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
end;

