      function CF_229Formula return Number is
CURSOR cur_INS_CLASS IS 

SELECT (DIKAIOD_LABOR_PRCN *100) DIKAIOD_LABOR_PRCN
FROM  PEN_CALC_NAT_LOWEST_DIKAIOD
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR
AND ACCOUNT_NO_DIKAIOD = :P_ACC_ACCOUNT_NO;

V_AMOUNT NUMBER;
begin

  OPEN cur_INS_CLASS;
  FETCH cur_INS_CLASS
  INTO V_AMOUNT;
  CLOSE cur_INS_CLASS;
  :CP_229 := V_AMOUNT;
  
  RETURN (ROUND(V_AMOUNT,2));
  END;

