      function CF_OLD_KATAV_DIKAIODFormula return Number is
V_AMOUNT NUMBER;

--30/7/2019

CURSOR cur_OLD_KATAV IS 
SELECT DISTINCT OLD_AMT_PRO_FOROU_THAN
FROM  PEN_CALC_NAT_LOWEST_DIKAIOD
