      function AfterPForm return boolean is
cursor c1 is
SELECT COM_ORG_BRANCHES.BRANCH_NAME, COM_ORG_BRANCHES.BRANCH_CODE,PEN_PRODUCT_PER_INSTITUTIONS.INTRODUCTION_CODE
 FROM REG_INSURED, 
      PEN_APPLICATION_INSTANCES, 
	    COM_ORG_BRANCHES, 
	    PEN_BE_PER_PRODINST, 
	    PEN_PRODUCT_PER_INSTITUTIONS,
	    PEN_PRODUCTS,
	    COM_PENSION_IKA_INSTITUTION
 WHERE PEN_APPLICATION_INSTANCES.APPLICATION_INCR_SEQ_NO=:P_APPL_INCR_SEQ_NO
   AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_UNIT_CODE=:P_APPL_UNIT_CODE
   AND PEN_APPLICATION_INSTANCES.PDTA_DOCUMENT_TYPE_APPL_CODE='00001'
   AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_YEAR=:P_APPL_YEAR
   AND PEN_APPLICATION_INSTANCES.INSURED_ID=:P_INSURED_ID
   AND REG_INSURED.INSURED_ID=PEN_APPLICATION_INSTANCES.INSURED_ID
   AND PEN_BE_PER_PRODINST.BE_PER_PRODINST_CODE=:P_BE_PER_PRODINST
   AND PEN_BE_PER_PRODINST.PRODUCT_PER_INSTITUTION_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_PER_INSTITUTION_CODE
   AND COM_PENSION_IKA_INSTITUTION.PENSION_IKA_INST_CODE=PEN_PRODUCT_PER_INSTITUTIONS.INSTITUTION_CODE
   AND PEN_PRODUCTS.PRODUCT_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE
   AND COM_ORG_BRANCHES.BRANCH_CODE=:P_DT_DEC_UNIT_CODE_SR;
 
cursor c3 is
SELECT count(1)
 FROM PEN_EFKA_DAYS_HDR b
WHERE B.insured_id                 = :P_INSURED_ID
 AND  B.PDTA_APPLICATION_UNIT_CODE = :P_APPL_UNIT_CODE 
 AND  B.PDTA_APPLICATION_YEAR      = :P_APPL_YEAR 
 AND  B.APPLICATION_INCR_SEQ_NO    = :P_APPL_INCR_SEQ_NO ;

lc3 Number;


cursor c_qual is
select nvl(c.qual_flg,0) 
    from pen_product_per_institutions b,
         pen_introductions            c
 where 1=1
  and  b.introduction_code            = c.introduction_code
  and  b.product_per_institution_code = :P_PRODINST
;


cursor c_wrk is 
select a.dec_orgbra_code||' / '||a.dec_year||' / '||a.dec_sid 
from wrk_decisions a
where a.status   = '1'
and   a.pen_unit = :P_DT_DEC_UNIT_CODE_SR
and   a.pen_year = :P_DT_DECISION_YEAR_SR
and   a.pen_no   = :P_DEC_INCR_SEC_NO_SR
;


---- pollaples thanatou TSAY-TSMEDE ktl.  (NT - 16/11/2020)
cursor c2 is
SELECT VALUE --- (ΝΑΙ=1,ΟΧΙ=0,ΔΕΝ ΑΦΟΡΑ=2)
   FROM PEN_DEC_FACT_TYPES_INSTANCE
 WHERE 1=1  
   AND  PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_INCR_SEQ_NO_SR        = :P_DT_INCR_SEC_NO_DIR 
   AND  PEN_DEC_FACT_TYPES_INSTANCE.DI_DECISION_YEAR_SR          = :P_DT_DECISION_YEAR_DIR  
   AND  PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_UNIT_CODE_SR          = :P_DT_DEC_UNIT_CODE_DIR 
   AND  PEN_DEC_FACT_TYPES_INSTANCE.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' 
   AND  PEN_DEC_FACT_TYPES_INSTANCE.INS_INSURED_ID               = :P_INSURED_ID 
   AND  PEN_DEC_FACT_TYPES_INSTANCE.TITLE_CODE                   = '00661'   --ΠΟΛΛΑΠΛΗ ΘΑΝΑΤΟΥ
   AND  PEN_DEC_FACT_TYPES_INSTANCE.DEC_FACT_TYPE_CODE           = '00809'   --ΠΟΛΛΑΠΛΗ ΘΑΝΑΤΟΥ   
   ;

l_pollapli_thanatou varchar2(12);


CURSOR cur_oga IS
SELECT 1 
FROM pen_product_per_institutions A,  
     pen_introductions B
WHERE A.introduction_code = B.introduction_code 
 AND  A.prodinst_description LIKE '%ΟΓΑ%'
 AND  A.product_per_institution_code = :P_PRODINST
; 

l_IS_OGA number := 0;
 


cursor c_E_KEYS is
SELECT a.E_DEC_NO,
       a.E_DEC_YEAR||'/'||a.E_DEC_NO||'*' ,
       a.EPIFILAKSI 
  FROM PEN_DECISION_INSTANCE a
 where dt_decision_year = :P_DT_DECISION_YEAR
  and  dec_incr_seq_no  = :P_DEC_INCR_SEC_NO
  and  dt_dec_unit_code = :P_DT_DEC_UNIT_CODE
  ;

l_dec_no VARCHAR2(100); 


L_EPIFILAKSI   VARCHAR2(1);

cursor c_Fast_Track is
select count(1) cnt
from   pen_dec_fact_types_instance a
where  a.di_document_type_dec_coce_sr = '1'  
and    a.status 			                = '1'
and    a.ins_insured_id               = :p_insured_id 
and    a.di_dec_incr_seq_no_sr        = :P_DT_INCR_SEC_NO_DIR 
and    a.di_decision_year_sr          = :P_DT_DECISION_YEAR_DIR 
and    a.di_dec_unit_code_sr          = :P_DT_DEC_UNIT_CODE_DIR 
and    a.title_code                   = '04921'   
and    a.dec_fact_type_code           = '04921' 
and    a.value	                       = '4'   --- 4 -fast track / 2 -non fast track    
;

cursor c_anagnoriseis is
select count(1)
  from pen_ops.Pen_Decision_Instance pdin, 
       Wrk_In_Out wiou, 
       Wrk_Application wapp, 
       Web_Wrk_Appl_EFKA wwae,
       Web_Wrk_EFKA_Cont_Work wecw, 
       Pen_Auto_Ins_Hist paih
where pdin.PAI_PDTA_Application_Unit_Code = wiou.Protocol_Orgbra_Code
   and pdin.PAI_PDTA_Application_Year      = wiou.Protocol_Year
   and pdin.PAI_Application_Incr_Seq_No    = wiou.Protocol_No
   and wiou.Ref_Appl_SID                   = wapp.Appl_SID
   and wapp.Appl_Protocol_Orgbra_Code      = wwae.Appl_Protocol_Orgbra_Code
   and wapp.Appl_Protocol_Year             = wwae.Appl_Protocol_Year               
   and wapp.Appl_Protocol_No               = to_char(wwae.Appl_Protocol_No)
   and wecw.Appl_SID                       = wwae.Appl_SID
   and paih.Call_ID                        = wecw.WS_Iah_Call_ID
   and paih.RecType                        = 5
   and pdin.Status                         = '1'
   and pdin.dt_dec_unit_code               = :P_DT_DEC_UNIT_CODE_SR
   and pdin.dt_decision_year               = :P_DT_DECISION_YEAR_SR
   and pdin.dec_incr_seq_no	               = :P_DEC_INCR_SEC_NO_SR
  ;
  
l_anagnoriseis number:=0;

cursor cur_is_aytomati is
select count(1) 
from  pen_dec_fact_types_instance a
where a.di_document_type_dec_coce_sr = '1'  
and   a.status                       = '1'
and   a.ins_insured_id               = :p_insured_id 
and   a.di_dec_incr_seq_no_sr        = :P_DT_INCR_SEC_NO_DIR 
and   a.di_decision_year_sr          = :P_DT_DECISION_YEAR_DIR 
and   a.di_dec_unit_code_sr          = :P_DT_DEC_UNIT_CODE_DIR 
and   a.title_code                   = '00001' 
and   a.dec_fact_type_code           = '88888' 
; 

l_is_aytomati  number :=0;
 
  
begin
 	
 	open c1;
	fetch c1 into :p_branch_name, :p_branch_code, :P_INTRODUCTION_CODE;
	close c1;
	
	open c2; 
	 fetch c2 into l_pollapli_thanatou;
	close c2; 

--  SRW.MESSAGE(100,:P_DT_INCR_SEC_NO_SR);
--  SRW.MESSAGE(100,:P_DT_DECISION_YEAR_SR);
--  SRW.MESSAGE(100,:P_DT_DEC_UNIT_CODE_SR);
--  SRW.MESSAGE(100,:P_INSURED_ID);
--  SRW.MESSAGE(100,:P_ACC_ACCOUNT_NO_DIR);

  if nvl(l_pollapli_thanatou,'0') = '1' 
  	then 
  	:P_POLLAPLI_THANATOU := 1;
  else
    :P_POLLAPLI_THANATOU := 0;
  end if;
  
 -- ΗΜΕΡΕΣ ΑΛΛΩΝ ΦΟΡΕΩΝ 
  open c3; 
	 fetch c3 into lc3;
	close c3; 
	if nvl(lc3,0) >= 1 
	  then :p_application_efka_days := 1;
	  else :p_application_efka_days := 0;
	end if; 

  -- ΘΕΜΕΛΙΩΝΕΙ ? 
	open c_qual;
	 fetch c_qual into :P_QUAL_FLG;
	close c_qual; 
   
  --srw.message(100,':P_ACC_ACCOUNT_NO : '||:P_ACC_ACCOUNT_NO);
  
  if :p_branch_code = '00054' then
  	if :p_commit_date <= to_date('18/06/2020','dd/mm/yyyy') then 
  		 :p_branch_name := 'ΠΕΡΙΦΕΡΕΙΑΚΗ ΔΙΕΥΘΥΝΣΗ ΣΥΝΤΑΞΕΩΝ Ν.Π.Δ.Δ.';                                                                      
  	elsif :p_commit_date >= to_date('19/06/2020','dd/mm/yyyy') then 	
  		 :p_branch_name    := 'Β''''Δ/ΝΣΗ ΑΠΟΝΟΜΗΣ ΣΥΝΤΑΞΕΩΝ & ΕΦΑΠΑΞ ΔΗΜΟΣΙΟΥ ΤΟΜΕΑ';
  		 :P_BRANCH_2_00054 := 'Tμήμα:Α''''ΤΜ. ΑΠΟΝΟΜΗΣ ΚΥΡΙΑΣ ΣΥΝΤΑΞΗΣ, ΕΠΙΚΟΥΡΙΚΗΣ & ΕΦΑΠΑΞ ΠΑΡΟΧΗΣ - ΝΠΔΔ' ;  
  	end if;	  
	end if; 
	
	open c_wrk;
	 fetch c_wrk into :P_WRK_DEC_NO;
	close c_wrk;


  -- ΕΙΝΑΙ ΟΓΑ Η ΥΠΑΓΩΓΗ?
  open cur_oga;
   fetch cur_oga into l_IS_OGA ;
  close cur_oga;
   
  IF ( :P_PRODINST IN ( '1352','21352','1353','1224','11352','1202','3353','1353','21352','1224','3353','4353','21352','4353',
                        '1353','1224','1436','11352','1202','1352','11352','1202',
                        '22352' -- CHRYS 20/7/2022
                        ) or l_IS_OGA = 1 )
  THEN :P_IS_OGA := 1;
  ELSE :P_IS_OGA := 0;
  END IF;	
  
  open  cur_is_aytomati;
  fetch cur_is_aytomati into l_is_aytomati;
  close cur_is_aytomati;
  
  -- ΑΥΤΟΜΑΤΗ ΑΠΟΦΑΣΗ ΜΕ ΗΛΕΚΤΡΟΝΙΚΗ ΥΠΟΓΡΑΦΗ
  open  c_E_KEYS;
	fetch c_E_KEYS into l_dec_no, :p_e_yyyyaa, L_EPIFILAKSI; 
	close c_E_KEYS;
		
 		
	if l_dec_no is not null then 
	   :p_e_yyyyaa :=	'*e-'||:p_e_yyyyaa;
	else
	 	 :p_e_yyyyaa := null;
	end if;	 
	
	-- FAST_TRACK ΑΥΤΟΜΑΤΩΝ ΑΠΟΦΑΣΕΩΝ
  open  c_Fast_Track;
	fetch c_Fast_Track into :P_FAST_TRACK;
	close c_Fast_Track;
 
  -- ΕΠΙΦΥΛΑΞΗ ΑΠΟ ΑΥΤΟΜΑΤΕΣ ΑΠΟΦΑΣΕΙΣ
  if l_dec_no is not null or nvl(l_is_aytomati,0) > 0 then
  	:p_is_aytomati := 1;
  end if;
  	
  
		
		--- 23/08/2022 ΟΤΑΝ ΕΚΔΙΔΟΝΤΑΙ ΑΥΤΟΜΑΤΟΠΟΙΗΜΕΝΕΣ ΑΠΟΦΑΣΕΙΣ ΜΕ ΑΝΑΓΝΩΡΙΣΕΙΣ ΘΑ ΕΜΦΑΝΙΖΕΤΑΙ ΣΥΓΚΕΚΡΙΜΕΝΟ ΚΕΙΜΕΝΟ ΣΤΟ ΔΙΑΤΑΚΤΙΚΟ -MAIL ΑΠΟ 22/08/2022 PDROUVAS+ΑΒΑΛΙΑΝ+ΑΜΕΤΑΧΑ
	  open  c_anagnoriseis;
	  fetch c_anagnoriseis into l_anagnoriseis;
	  close c_anagnoriseis;
	  
	  
	  
	  if nvl(l_anagnoriseis,0) > 1 
	  	then :P_anagnoriseis := 1; 
	    else :P_anagnoriseis := 0;
	  end if; 	
	  
	  
--	  SRW.MESSAGE(100,' :P_anagnoriseis :'|| :P_anagnoriseis);
--	  SRW.MESSAGE(100,' :P_FAST_TRACK :'|| :P_FAST_TRACK);	                                                     
--    SRW.MESSAGE(100,' :L_EPIFILAKSI :'|| L_EPIFILAKSI);
	  
	  if NVL(:P_anagnoriseis,0) > 0 
	    then :p_epifylaxi := 'Επιφυλασσόμεθα για την τροποποίηση της παρούσας απόφασης ως προς τον χρόνο ασφάλισης '||chr(10)||
	                         ' που θα προκύψει απο την έκδοση αναγνωριστικής απόφασης, καθώς επίσης και για τον τρόπο '||chr(10)||
	                         ' αποπληρωμής του νέου ασφαλιστικού χρόνου.';
	  else
	  		if l_epifilaksi = '1' then
		    :p_epifylaxi := 'Επιφυλασσόμεθα για τυχόν αναθεώρηση της παρούσας απόφασης μετά απο επανεξέταση στοιχείων της   '||
		                    ' συνταξιοδοτικής σας περιπτώσης';
	  		else
	  		:p_epifylaxi := null;	
		    end if;	
	  end if;	
			
    IF :p_dt_dec_unit_code  = '09930' THEN
	  	:P_NOTES := 'Κατά της απόφασης αυτής μπορείτε να ασκήσετε έφεση ενώπιον του Αρμοδίου Τμήματος '||
	  	            'του Ελεγκτικού Συνεδρίου εντός 60 ημερών (ν.4700/2020 άρθρα 111, 113, 352 & 354) '||
	  	            'από την κοινοποίησή της. Σε κάθε περίπτωση η κοινοποίηση θεωρείται ότι έγινε την '||
	  	            'εξηκοστή μέρα από την ημερομηνία που αναγράφεται στην απόφαση αυτή. ' ;
	  END IF;	
	  	
	  IF :p_dt_dec_unit_code  = '09932' THEN
	  	:P_NOTES := 'Αν για οποιονδήποτε λόγο δεν συμφωνείτε με το περιεχόμενο της ανωτέρω Πράξης, μπορείτε '||
	  	            'να ασκήσετε κατ'' αυτής έφεση ενώπιον του Αρμοδίου Τμήματος του Ελεγκτικού Συνεδρίου εντός 60 ημερών '||
	  	            '(ν.4700/2020 άρθρα 111,113, 352 & 354) από την κοινοποίηση του εγγράφου. Η κοινοποίηση της πράξης '||
	  	            'θεωρείται ότι έγινε την εξηκοστή μέρα από την ημερομηνία που φέρει το έγγραφο αυτό. ' ;
	  END IF;	

  return (TRUE);
end;

