      function CF_FIND_YY_MM_DDFormula return Number is
lidaysofmonth number:= 25;


CURSOR C_TRANS_TYPE IS 
SELECT DISTINCT NVL(B.DAYS_30_FLAG,'0')--, A.TRANS_DESCR   
FROM COM_INSURANCE_HISTORY_TYPES A,
     PEN_TRANS_TYPES             B,
     PEN_INSURED_DAYS            C
WHERE C.TRANSACTION_TYPE  = B.TRANSACTION_TYPE
AND   A.TRANS_TYPE        = C.INSHISTYP_TRANS_TYPE 
AND   C.INS_INSURED_ID    = :P_INSURED_ID
AND   A.TRANS_TYPE        = :TRANS_TYPE
;

l_days_flg varchar2(1);


begin
   
 -- SRW.MESSAGE(100, ':PENSION_INST_CODE : '||:PENSION_INST_CODE);
 -- SRW.MESSAGE(100, 'P_INSURED_ID : '||:P_INSURED_ID);
 -- SRW.MESSAGE(100, 'TRANS_TYPE : '||:TRANS_TYPE);
  
	
	:CP_YEARS     := null;
  :CP_MONTHS    := null;
  :CP_DAYS      := null;
 
 

  open  C_TRANS_TYPE;
  fetch C_TRANS_TYPE into l_days_flg;
  close C_TRANS_TYPE;
  
  
  if nvl(l_days_flg,'0') = '1'
  	then lidaysofmonth := 30;  --- πχ στρατιωτικες θητειες
  	else lidaysofmonth := 25;
  end if; 
 
  -- Call the procedure
  com_util_days.convdaysinyearsmontsdays(pisumofdays   => :INSURANCE_DAYS,
                                         pidaysofmonth => lidaysofmonth,
                                         poyears       => :CP_YEARS,
                                         pomonths      => :CP_MONTHS,
                                         podays        => :CP_DAYS);
	

  return (:CP_YEARS);


exception when others then return null;

  	
end;

      function CF_FIND_TOT_YYMMDDFormula return Number is

begin
  
  --SRW.MESSAGE(100, ':P_SID :'||:P_SID);
  :CP_TOT_YEARS     := null;
  :CP_TOT_MONTHS    := null;
  :CP_TOT_DAYS      := null;
  -- Call the procedure
  com_util_days.convdaysinyearsmontsdays(pisumofdays   => :sum_insurance_days,
                                         pidaysofmonth => :CALC_DAYS,
                                         poyears       => :CP_TOT_YEARS,
                                         pomonths      => :CP_TOT_MONTHS,
                                         podays        => :CP_TOT_DAYS);
  

  return (:CP_TOT_YEARS);


exception when others then return null;

    
end;

