SELECT ADAPODOTIKH_AMT
FROM  PEN_CALC_ADAPOD_RES_DA A
WHERE ACCOUNT_NO               = :P_ACC_ACCOUNT_NO 
AND   A.INSTITUTION_CODE_AYTOT = :INST_CODE_AYTOT
AND   AYTOT_DA_FLG             = '1'; 

begin
  
  OPEN CUR;
  FETCH CUR 
  INTO V_NUM;
  CLOSE CUR;
  
  
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
  
  OPEN CUR_2;
  FETCH CUR_2 
  INTO V_NUM_2;
  CLOSE CUR_2;
  
  
  IF V_NUM_2 IS NOT NULL AND V_NUM_2 != 0 THEN
  	RETURN V_NUM_2;
  ELSE
	  RETURN (NVL(V_NUM,0)*NVL(V_NUM_1,0))/100;
  END IF;
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
end;

      function CF_522Formula return Number is
begin
  RETURN NVL(:AVERAGE_INCOME1, :AVERAGE_INCOME_NO_RETRO_AYT);
end;

      function CF_POSA_AYTOTELOUSFormula return Number is

cursor c_sum_posa is
select 
       -- ΑΥΤΟΤΕΛΗ 
       SUM(decode(a.cp_calculation_parameter_code, 'ETHAF', nvl(a.amount,0), 0)) aytotelis_ethniki , --ΕΘΝΙΚΗ
       SUM(decode(a.cp_calculation_parameter_code, 'ANTAF', nvl(a.amount,0), 0)) aytotelis_adapod,   --ΑΝΤΑΠΟΔΟΤΙΚΗ
       -- ΔΙΑΔΟΧΙΚΑ 
       SUM(decode(a.cp_calculation_parameter_code, 'ETHSQ', nvl(a.amount,0), 0)) diadoxiki_ethniki , --ΕΘΝΙΚΗ
       SUM(decode(a.cp_calculation_parameter_code, 'ANTSQ', nvl(a.amount,0), 0)) diadoxiki_adapod    --ΑΝΤΑΠΟΔΟΤΙΚΗ
  from pen_qt_per_be_cc_per_account a
  where  1=1   
   and a.acc_account_no = :P_ACC_ACCOUNT_NO_DIR
   and a.status         = '1'
   ;
begin
	
	open  c_sum_posa;
	fetch c_sum_posa into :cp_ayto_ethniki, :cp_ayto_adapod, :cp_diadox_ethniki, :cp_diadox_adapod;
	close c_sum_posa;
  
  return  :cp_ayto_ethniki;
  exception when others then return 0;
end;

      function CF_SUM_POSA_AYTOTFormula return Number is
begin
  RETURN NVL(:cp_ayto_ethniki,0) + NVL(:cp_ayto_adapod,0);
  EXCEPTION WHEN OTHERS THEN RETURN 0;
end;

      function CF_SUM_POSA_DIADOXFormula return Number is
begin
  RETURN NVL(:cp_diadox_ethniki,0) + NVL(:cp_diadox_adapod,0);
  EXCEPTION WHEN OTHERS THEN RETURN 0;
end;

      function CF_SYMFEROTERO_POSOFormula return Char is

L_RET VARCHAR2(500);
begin
	
--	srw.message(100,'CF_SUM_POSA_AYTOT :'||:CF_SUM_POSA_AYTOT);
	--srw.message(100,'CF_SUM_POSA_DIADOX :'||:CF_SUM_POSA_DIADOX);
 IF NVL(:CF_SUM_POSA_AYTOT,0) > NVL(:CF_SUM_POSA_DIADOX,0)
 	THEN 
 	     :CP_SYMFEROTERO_POSO := NVL(:CF_SUM_POSA_AYTOT,0) - NVL(:CF_PLAFON,0); -- CHRYS 1/7/2022 PLAFON
 	     L_RET := 'ΑΥΤΟΤΕΛΗΣ  '||TO_CHAR(NVL(:CF_SUM_POSA_AYTOT,0));   
  ELSE 
 	     :CP_SYMFEROTERO_POSO := NVL(:CF_SUM_POSA_DIADOX,0);
 	     L_RET := 'ΔΙΑΔΟΧΙΚΗ  '||TO_CHAR(NVL(:CF_SUM_POSA_DIADOX,0));   
 END IF;
 
 ----
 IF NVL(:CF_SUM_POSA_AYTOT,0) > NVL(:CF_SUM_POSA_DIADOX,0) THEN
	  IF NVL(:CF_SUM_POSA_AYTOT,0) > :CP_KO_ERG  THEN
	     :CP_FINAL_SYMFEROTERO :=  NVL(:CF_SUM_POSA_AYTOT,0);
	  ELSE
	  	 :CP_FINAL_SYMFEROTERO :=  :CP_KO_ERG;
	  END IF; 
 ELSE
	  IF NVL(:CF_SUM_POSA_DIADOX,0) > :CP_KO_ERG  THEN
	     :CP_FINAL_SYMFEROTERO :=  NVL(:CF_SUM_POSA_DIADOX,0) - NVL(:CF_PLAFON,0); -- CHRYS 1/7/2022 PLAFON;
	  ELSE
	  	 :CP_FINAL_SYMFEROTERO :=  :CP_KO_ERG;
	  END IF;  	
 END IF;	 
 RETURN L_RET; 
 EXCEPTION WHEN OTHERS THEN NULL; 
end;

      function CF_477Formula return Number is
begin
  IF :INST_CODE_0075_DA IS NOT NULL
  	THEN :CP_HAS_0075_DIAD := 1;
    ELSE :CP_HAS_0075_DIAD := 0;
  END IF; 
  RETURN 0;
  EXCEPTION WHEN OTHERS THEN RETURN 0;  
end;

      function CF_19_BFormula return Number is
V_NUM	  NUMBER;
V_NUM_1	NUMBER;

/*CURSOR CUR IS
SELECT ADAPODOTIKH_AMT
FROM PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO; 
*/
CURSOR CUR_1 IS
SELECT  FINAL_NAT_PENSION_AMT
FROM  PEN_CALC_NATIONAL_RES_DA A
WHERE ACCOUNT_NO               = :P_ACC_ACCOUNT_NO 
AND   AYTOT_DA_FLG             = '2'
;

begin
  
 /* OPEN CUR;
  FETCH CUR 
  INTO V_NUM;
  CLOSE CUR;
  */
  
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
  
  
  RETURN NVL(V_NUM_1,0);
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
end;

      function CF_22_BFormula return Number is
V_NUM	  NUMBER;
V_NUM_1	NUMBER;
V_NUM_2	NUMBER;

CURSOR CUR IS
SELECT  ((sum(NVL(MONTH_INCOME_INFLATED,0)+NVL(RETRO_AMT_INFLATED,0))*25)/sum(NVL(MONTH_DAYS,0)))  
FROM  PEN_CALC_ADAPOD_RES_DA A
WHERE ACCOUNT_NO               = :P_ACC_ACCOUNT_NO 
AND   AYTOT_DA_FLG             = '1' 
;

CURSOR CUR_1 IS
SELECT   NVL(POSOSTO_ANAPL,0)+ NVL(ADAPOD_PERCENT_KSB,0)
FROM  PEN_CALC_ADAPOD_RES_DA A
WHERE ACCOUNT_NO               = :P_ACC_ACCOUNT_NO 
AND   AYTOT_DA_FLG             = '1'
;

CURSOR CUR_2 IS
SELECT ADAPODOTIKH_AMT
FROM  PEN_CALC_ADAPOD_RES_DA A
WHERE ACCOUNT_NO               = :P_ACC_ACCOUNT_NO 
AND   AYTOT_DA_FLG             = '1'
;

begin
  
  OPEN CUR;
  FETCH CUR 
  INTO V_NUM;
  CLOSE CUR;
  
  
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
  
  OPEN CUR_2;
  FETCH CUR_2 
  INTO V_NUM_2;
  CLOSE CUR_2;
  
  
  IF V_NUM_2 IS NOT NULL AND V_NUM_2 != 0 THEN
  	RETURN V_NUM_2;
  ELSE
	  RETURN (NVL(V_NUM,0)*NVL(V_NUM_1,0))/100;
  END IF;
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
end;

      function CF_23_BFormula return Number is
begin
  return (:cf_19_B+:cf_22_B);
end;

      function B_67FormatTrigger return boolean is
