function CF_511Formula return Number is
V_NUM_1 NUMBER;

CURSOR CUR_1 IS
SELECT  TOTAL_AMOUNT
FROM  PEN_CALC_NATIONAL_RES_DA
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO;


begin
 --CHRYS 25/5/2018   RETURN (NVL(:CF_23,0) + NVL(:CF_50,0));
  
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
  
  
  RETURN NVL(V_NUM_1,0) + NVL(:CF_50,0);
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;

END;

      function CF_499Formula return Number is
 v_NUM NUMBER;
    
    CURSOR Cur_NUM IS
   SELECT NVL(NEW_AMOUNT,0) - NVL(SPECIAL_CONTRIBUTION_NEW,0) -NVL(SPECIAL_CONTR_BEF_60_NEW,0)-NVL(SICKNESS_DEDUCTION_NEW,0)
FROM PEN_EFKA_PERSONAL_DIFFERENCE
WHERE ACCOUNT_NO =:P_ACC_ACCOUNT_NO;   

begin
  
  
                 OPEN Cur_NUM;
                  FETCH Cur_NUM
                  INTO v_NUM;
                  CLOSE Cur_NUM;
                  
             RETURN v_NUM;
            
	     
end;

      function CF_PLAFONFormula return Number is

V_PLAFON		NUMBER;
CURSOR	CUR_PLAFON IS
SELECT AMOUNT
FROM   PEN_QT_PER_BE_CC_PER_ACCOUNT A,
			 PEN_ACCOUNT B
WHERE  B.ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND    B.ACCOUNT_NO = A.ACC_ACCOUNT_NO
AND    A.CP_CALCULATION_PARAMETER_CODE = 'PLAFN';
			 
begin

OPEN	CUR_PLAFON;
FETCH	CUR_PLAFON
INTO	V_PLAFON;
CLOSE	CUR_PLAFON;

RETURN (NVL(V_PLAFON,0));


end;

