      function CF_21_DFormula return Number is
V_NUM	  NUMBER;
V_NUM_1	NUMBER;
V_NUM_2	NUMBER;

CURSOR CUR IS
SELECT  ((sum(NVL(MONTH_INCOME_INFLATED,0)+NVL(RETRO_AMT_INFLATED,0))*25)/sum(NVL(MONTH_DAYS,0)))  
FROM  PEN_CALC_ADAPOD_RES_DA A
WHERE ACCOUNT_NO               = :P_ACC_ACCOUNT_NO
AND   AYTOT_DA_FLG             = '2'; 

CURSOR CUR_1 IS
SELECT   NVL(POSOSTO_ANAPL,0)+ NVL(ADAPOD_PERCENT_KSB,0)
FROM  PEN_CALC_ADAPOD_RES_DA A
WHERE ACCOUNT_NO               = :P_ACC_ACCOUNT_NO
AND   AYTOT_DA_FLG             = '2'; 

CURSOR CUR_2 IS
SELECT ADAPODOTIKH_AMT
FROM  PEN_CALC_ADAPOD_RES_DA A
WHERE ACCOUNT_NO               = :P_ACC_ACCOUNT_NO
AND   AYTOT_DA_FLG             = '2'; 

begin
  
  OPEN CUR;
  FETCH CUR 
  INTO V_NUM;
  CLOSE CUR;
  
  
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
  
  OPEN CUR_2;
  FETCH CUR_2 
  INTO V_NUM_2;
  CLOSE CUR_2;
  
  
  IF V_NUM_2 IS NOT NULL AND V_NUM_2 != 0 THEN
  	RETURN V_NUM_2;
  ELSE
	  RETURN (NVL(V_NUM,0)*NVL(V_NUM_1,0))/100;
  END IF;
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
end;

function CF_GET_POSA_DIKFormula return Number is
------------ cursor c_posa_melous is select sum(x.ethn_melos), sum(x.adap_melos), sum(x.pd_melos), sum(x.pd_n4670_melos), sum(x.synolo_syntaxis_melos), sum(x.palio_katabalomeno_melos), sum(x.ergatiko_melos), sum(x.ko_melos), sum(x.symferotero_melos), --OGA sum(x.OGA_KYRIA_MELOS), sum(x.OGA_BASIKH_MELOS), sum(x.OGA_ETHNIKI_MELOS), sum(x.OGA_ADAPODOTIKH_MELOS), sum(x.OGA_KO_MELOS), sum(x.OGA_SYMFEROTERO_MELOS), sum(x.OGA_SYNOLO_SYNT_MELOS) -- sum(x.ergatiko_melos) from ( select decode(a.cp_calculation_parameter_code, 'MAEBT', nvl(a.amount,0), 0) ethn_melos, --- ΕΘΝΙΚΗ decode(a.cp_calculation_parameter_code, 'MAABT', nvl(a.amount,0), 0) adap_melos, --- ΑΝΤΑΠΟΔΟΤΙΚΗ decode(a.cp_calculation_parameter_code, 'MPDS2', nvl(a.amount,0), 0) pd_melos , --- ΠΔ decode(a.cp_calculation_parameter_code, 'MDIAF', nvl(a.amount,0), 0) pd_n4670_melos , --- ΠΔ Ν4670 decode(a.cp_calculation_parameter_code, 'MTOTP', nvl(a.amount,0), 0) synolo_syntaxis_melos , --- ΣΥΝΟΛΟ ΣΥΝΤΑΞΗΣ ----TO BE CHECKED decode(a.cp_calculation_parameter_code, 'MKTBF', nvl(a.amount,0), 0) palio_katabalomeno_melos, --- ΠΑΛΙΟ ΚΑΤΑΒΑΛΟΜΕΝΟ decode(a.cp_calculation_parameter_code, 'MLABR', nvl(a.amount,0), 0) ergatiko_melos, --- ΠΟΣΟ ΕΡΓΑΤΙΚΟΥ decode(a.cp_calculation_parameter_code, 'MLLIM', nvl(a.amount,0), 0) ko_melos, --- ΚΟ decode(a.cp_calculation_parameter_code, 'MBESA', nvl(a.amount,0), 0) symferotero_melos, --- ΣΥΜΦΕΡΟΤΕΡΟ ΜΕΛΟΥΣ ---- για ΟΓΑ decode(a.cp_calculation_parameter_code, 'OMKYR', nvl(a.amount,0), 0) - decode(a.cp_calculation_parameter_code, 'OMKDR', nvl(a.amount,0), 0) OGA_KYRIA_MELOS, --- KYRIA decode(a.cp_calculation_parameter_code, 'OMBAM', nvl(a.amount,0), 0) - decode(a.cp_calculation_parameter_code, 'OMBDR', nvl(a.amount,0), 0) OGA_BASIKH_MELOS, --- BASIKH decode(a.cp_calculation_parameter_code, 'MAEBT', nvl(a.amount,0), 0) - decode(a.cp_calculation_parameter_code, 'OMEDR', nvl(a.amount,0), 0) OGA_ETHNIKI_MELOS , --- ETHNIKH decode(a.cp_calculation_parameter_code, 'MAABT', nvl(a.amount,0), 0) - decode(a.cp_calculation_parameter_code, 'OMADR', nvl(a.amount,0), 0) OGA_ADAPODOTIKH_MELOS , --- ANTAPODOTIKH decode(a.cp_calculation_parameter_code, 'OMLLM', nvl(a.amount,0), 0) OGA_KO_MELOS , --- KO decode(a.cp_calculation_parameter_code, 'MBES3', nvl(a.amount,0), 0) OGA_SYMFEROTERO_MELOS, --- ΣΥΜΦΕΡΟΤΕΡΟ ΜΕΛΟΥΣ -- SYNOLO decode(a.cp_calculation_parameter_code, 'OMKYR', nvl(a.amount,0), 0) - decode(a.cp_calculation_parameter_code, 'OMKDR', nvl(a.amount,0), 0) + --- KYRIA decode(a.cp_calculation_parameter_code, 'OMBAM', nvl(a.amount,0), 0) - decode(a.cp_calculation_parameter_code, 'OMBDR', nvl(a.amount,0), 0) + --- BASIKH decode(a.cp_calculation_parameter_code, 'MAEBT', nvl(a.amount,0), 0) - decode(a.cp_calculation_parameter_code, 'OMEDR', nvl(a.amount,0), 0) + --- ETHNIKH decode(a.cp_calculation_parameter_code, 'MAABT', nvl(a.amount,0), 0) - decode(a.cp_calculation_parameter_code, 'OMADR', nvl(a.amount,0), 0) OGA_SYNOLO_SYNT_MELOS --- ADAPODOTIKH --decode(a.cp_calculation_parameter_code, 'MLABR', nvl(a.amount,0), 0) ergatiko_melos --- ΠΟΣΟ ΕΡΓΑΤΙΚΟΥ
from pen_qt_per_be_cc_per_account a, pen_qualifying_term_per_be_cc b, pen_qualifying_term_per_cc c, pen_be_per_calcul_category d, pen_calculation_category e, pen_be_per_qual_cat f, pen_be_per_prodinst g, pen_bussiness_events h where 1=1 and a.acc_account_no = :P_ACC_ACCOUNT_NO and a.status = '1' and a.bcc_qual_term_per_be_cc_code = b.qual_term_per_be_cc_code and b.qualif_term_per_cc_code = c.qualif_term_per_cc_code and c.be_per_calcul_category_co = d.be_per_calcul_category_code and d.calculation_category_code = e.calculation_category_code and d.be_per_qual_category_code = f.be_per_qual_category_code and f.be_per_prodinst_code = g.be_per_prodinst_code and g.buss_event_code = h.buss_event_code ) x ;
begin -- srw.message(100, ' P_ACC_ACCOUNT_NO ' ||:P_ACC_ACCOUNT_NO); ---------------------------------------------- open c_posa_melous; fetch c_posa_melous into :cp_ethn_melos, :cp_adap_melos, :cp_pd_melos, :cp_pd_n4670_melos, :cp_synolo_syntaxis_melos, :cp_palio_katabalomeno_melos, :cp_ergatiko_melos, :cp_ko_melos, :cp_symferotero_melos, --OGA :cp_OGA_KYRIA_MELOS, :cp_OGA_BASIKH_MELOS, :cp_OGA_ETHNIKI_MELOS, :cp_OGA_ADAPODOTIKH_MELOS, :cp_OGA_KO_MELOS, :cp_OGA_SYMFEROTERO_MELOS, :cp_OGA_SYNOLO_SYNT_MELOS ; close c_posa_melous;
return (:cp_ethn_melos); exception when others then return 0; end;

