      function CF_PAD_IDFormula return Number is -- CHRYS 1/9/2022
CURSOR CUR_PAD_ID_DEATH IS
SELECT  DISTINCT B.PAD_ID
FROM    PEN_ACCOUNT A,
        PEN_APPLICATION_DA_DEATH B
WHERE   A.ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND     A.PAI_PDTA_APPLICATION_UNIT_CODE = B.PDTA_APPLICATION_UNIT_CODE
AND     A.PAI_PDTA_APPLICATION_YEAR = B.PDTA_APPLICATION_YEAR
AND     A.PAI_APPLICATION_INCR_SEQ_NO = B.APPLICATION_INCR_SEQ_NO
AND     B.STATUS = '1'; 

V_PAD_ID		NUMBER;

begin
V_PAD_ID := NULL;
OPEN    CUR_PAD_ID_DEATH;
FETCH   CUR_PAD_ID_DEATH
INTO    V_PAD_ID;
CLOSE   CUR_PAD_ID_DEATH;
--SRW.MESSAGE(100,'P_ACC_ACCOUNT_NO :'||:P_ACC_ACCOUNT_NO); 
--SRW.MESSAGE(100,'V_PAD_ID :'||V_PAD_ID); 
RETURN V_PAD_ID;


end;

      function CF_BASIKH_OGAFormula return Number is

cursor c_basiki_oga is
select 
       -- ΟΓΑ 
       -- CHRYS decode(a.cp_calculation_parameter_code, 'ODBAM', nvl(a.amount,0), 0) basiki_oga
       NVL(AMOUNT,0)
  from pen_qt_per_be_cc_per_account a
  where  1=1   
   and a.acc_account_no = :P_ACC_ACCOUNT_NO_DIR
   AND  a.cp_calculation_parameter_code =  'ODBAM'
   and a.status         = '1'
   and rownum = 1
   ;
l_poso number:= 0;

begin
	
	open  c_basiki_oga;
	fetch c_basiki_oga into l_poso;
	close c_basiki_oga;
  
  return  nvl(l_poso,0);
  exception when others then return 0;
end;

      function CF_OGA_PERCFormula return Number is

-- ΠΟΣΟΣΤΟ ΓΙΑ ΚΥΡΙΑ ΚΑΙ ΒΑΣΙΚΗ
CURSOR CUR_PRCN IS
SELECT DISTINCT PERCENT
FROM PEN_OGA_EE
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR
AND AMOUNT_TYPE = 'MINUS_KYRIA_DA';

V_PRCN NUMBER;

BEGIN
	OPEN CUR_PRCN;
	FETCH	CUR_PRCN
	INTO V_PRCN;
	CLOSE CUR_PRCN;
	RETURN V_PRCN;
	
	  
end;

      function CF_OGA_TELIKH_KYRIAFormula return Number is
L_RET NUMBER := 0;
begin
  -- CHRYS 6/7/2022 L_RET := (:CF_KYRIA_OGA + GREATEST(:CS_SUM_OGA_BEST_PART_AMNT,:CP_OGA_TMHMATIKO));
  L_RET := GREATEST (NVL(:CF_KYRIA_OGA,0) + NVL(:CS_SUM_OGA_BEST_PART_AMNT,0),NVL(:CP_OGA_TMHMATIKO,0) + NVL(:CS_SUM_OGA_BEST_PART_AMNT,0));
  RETURN L_RET;
  EXCEPTION WHEN OTHERS THEN RETURN 0;
end;

