      function CF_OGA_KO_TOTFormula return Number is
V_RET   NUMBER:=0;

CURSOR CUR_1 IS
SELECT LOWEST_LABOR_PENSION    
FROM  PEN_CALC_NATIONAL_RES_DA
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR; 


begin
  
  OPEN  CUR_1;
  FETCH CUR_1 INTO :CP_OGA_KO;
  CLOSE CUR_1;
  
  V_RET := :CP_OGA_KO*:CF_OGA_PERC;
  
  RETURN NVL(V_RET,0);
  
  EXCEPTION WHEN OTHERS THEN RETURN 0;
end;

      function CF_OGA_TELIKO_KATAVALOMENOForm return Number is
CURSOR CUR_ODKAT IS
SELECT AMOUNT
FROM PEN_QT_PER_BE_CC_PER_ACCOUNT 
WHERE ACC_ACCOUNT_NO = :P_ACC_ACCOUNT_NO 
AND CP_CALCULATION_PARAMETER_CODE = 'ODKAT';


V_AMT NUMBER;
begin
  OPEN CUR_ODKAT;
  FETCH CUR_ODKAT
  INTO V_AMT;
  CLOSE CUR_ODKAT;
  
  RETURN V_AMT; 
end;

      function CF_KYRIA_OGAormula return Number is

cursor c_kyria_oga is 
select a.kyria_oga_amount
from pen_oga_anal_amounts_da a,
     com_pension_ika_institution b
where a.account_no        = :P_ACC_ACCOUNT_NO_DIR
and   a.pension_inst_code = '00033' 
--and   rownum = 1
ORDER BY NVL(kyria_oga_amount,0) DESC
;
l_kyria number:=0;
begin
  open  c_kyria_oga;
  fetch c_kyria_oga into l_kyria;
  close c_kyria_oga;
  
  return nvl(l_kyria,0);
  exception when others then return 0;
	
end;

      function CF_OGA_POSO_20Formula return Number is

cursor c_posa is
select a.theorhtiko_amount,
       a.tmhmatiko_amount,
       a.oga_days,
       a.total_days
from pen_oga_anal_amounts_da a
where a.account_no = :P_ACC_ACCOUNT_NO_DIR
 and  a.theorhtiko_amount > 0
 ;
begin
  open  c_posa;
  fetch c_posa into :cp_oga_theoritiko, :cp_oga_tmhmatiko, :cp_oga_days, :cp_oga_total_days;
  close c_posa;
  
  return :cp_oga_theoritiko;
  exception when others then return 0;
end;

