      function B_345FormatTrigger return boolean is
begin
-- IF nvl(:p_is_aytomati,0) = 0 THEN --:p_e_yyyyaa IS NULL THEN 
--  	return (FALSE);
-- ELSE  	

	if NVL(:p_anagnoriseis,0) > 0 and :p_epifylaxi is not null 
		then return (TRUE);
	elsif NVL(:p_fast_track,0) > 0 and NVL(:p_anagnoriseis,0) = 0 
    then return(FALSE);
	elsif  :p_epifylaxi is not null  and NVL(:p_fast_track,0) = 0
		then return (TRUE);
  end if; 
 --END IF;	
 --- ΑΥΤΟ ΘΑ ΕΜΦΑΝΙΖΕΤΑΙ ΜΟΝΟ ΣΤΙΣ ΑΥΤΟΜΑΤΟΠΟΙΗΜΕΝΕΣ 13/09/2022 ΑΠΟ ΑΜΕΤΑΞΑ+ΑΜΠΑΛΙΑΝ
end;

