      function M_87FormatTrigger return boolean is
CURSOR CUR_2019 IS
SELECT DECODE(NVL(AFTER_01_01_2019_FLG,'0')||NVL(AFTER_01_10_2019_FLG,'0'),'00',0,1) 
  FROM PEN_INTRODUCTIONS
WHERE  INTRODUCTION_CODE = :P_INTRODUCTION_CODE;

V_2019 PEN_INTRODUCTIONS.AFTER_01_01_2019_FLG%TYPE;

begin
  -- ΓΙΑ ΥΠΑΓΩΓΕΣ ΠΟΥ ΕΙΝΑΙ ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/1/2019
  V_2019 := '0';
  
  OPEN CUR_2019;
  FETCH CUR_2019
  INTO V_2019;
	CLOSE CUR_2019;
	  
  IF V_2019 = 1 THEN
  	return (FALSE);
  ELSE
  	return (TRUE);
  END IF;
end;

